import {
  html,
  customElement,
  state,
  property,
} from "@umbraco-cms/backoffice/external/lit";
import { UmbPropertyEditorUiElement } from "@umbraco-cms/backoffice/property-editor";
import { UmbLitElement } from "@umbraco-cms/backoffice/lit-element";
import type { UUISelectEvent } from "@umbraco-cms/backoffice/external/uui";
import { PickerService } from "../../generated/services";
import { PickerItem } from "../../generated/models";

const elementName = "forms-document-type-picker-property-editor";

@customElement(elementName)
export class FormsDocumentTypePickerPropertyUiElement extends UmbLitElement implements UmbPropertyEditorUiElement {
	@state()
  _options: Array<PickerItem> = [];

  @property()
  value = "";

  async connectedCallback() {
    super.connectedCallback();

    await this.#loadDataTypes();
  }

  async #loadDataTypes() {
    const documentTypes = await PickerService.getPickerDocumentType();
    this._options = documentTypes;
  }

  #onChange(e: UUISelectEvent) {
    const newValue = e.target.value.toString();
    if (newValue === this.value) return;
    this.value = newValue;
    this.dispatchEvent(new CustomEvent("property-value-change"));
  }

  render() {
    return html`<uui-select
      label="Document type picker"
      @change=${this.#onChange}
      .options=${this._options.map((o) => ({
        name: o.value,
        value: o.id,
        selected: o.id === this.value,
      }))}
    >
    </uui-select>`;
  }
}

export default FormsDocumentTypePickerPropertyUiElement;

declare global {
	interface HTMLElementTagNameMap {
		[elementName]: FormsDocumentTypePickerPropertyUiElement;
	}
}
